df_figure = create_figure_dataframe()/7.14

df_provinces = df_figure.iloc[0:]

df_transposed = df_provinces.T

blues = ["#f7fbff", "#deebf7", "#c6dbef", "#9ecae1", "#6baed6", "#4292c6", "#08519c"]
cmap = LinearSegmentedColormap.from_list("academic_blues", blues, N=256)
vmin, vmax = df_transposed.values.min(), df_transposed.values.max()
norm = plt.Normalize(vmin, vmax)

fig, ax = plt.subplots(figsize=(20, 12))

n_times = len(df_transposed.index)
n_provinces = len(df_transposed.columns)
cell_size = min(20 / n_times, 12 / n_provinces) * 72

row_spacing_factor = 1.5

for i, time_point in enumerate(df_transposed.index):
    month_max = df_transposed.loc[time_point].max()
    for j, province in enumerate(df_transposed.columns):
        price = df_transposed.iloc[i, j]
        y_pos = j * cell_size * row_spacing_factor
        rect = patches.Rectangle((i * cell_size, y_pos), cell_size, cell_size,
                                 facecolor=cmap(norm(price)),
                                 edgecolor='white', linewidth=0.15)
        ax.add_patch(rect)
        if price == month_max:
            ax.add_patch(
                patches.Rectangle((i * cell_size, y_pos), cell_size, cell_size,
                                  linewidth=1.2, edgecolor='#b2182b', fill=False)
            )

ax.set_xlim(0, n_times * cell_size)
ax.set_ylim(0, n_provinces * cell_size * row_spacing_factor)

jan_idx = [0, 12, 24, 36, 48, 60, 72]
ax.set_xticks((np.array(jan_idx) + 0.5) * cell_size)
ax.set_xticklabels(['2014', '2015', '2016', '2017', '2018', '2019', '2020'],
                   fontsize=18)

ax.set_yticks((np.arange(n_provinces) + 0.5) * cell_size * row_spacing_factor)
ax.set_yticklabels(df_transposed.columns, fontsize=18)

divider = make_axes_locatable(ax)
cax = divider.append_axes("right", size="1%", pad=0.1)

sm = plt.cm.ScalarMappable(cmap=cmap, norm=norm)
sm.set_array([])
cbar = plt.colorbar(sm, cax=cax)
cbar.set_label('Coal Price ($/ton)', fontsize=18)
cbar.ax.tick_params(labelsize=20)

ax.set_aspect('equal')
ax.tick_params(axis='both', which='both', length=0)
plt.tight_layout()
plt.show()